use super::consts::GD_QA_MAX_ITER;
use super::group_delay_qa_profile::GroupDelayQaProfile;
use autoeq::Curve;
use autoeq::loss::calculate_standard_deviation_in_range;
use autoeq::loss::phase_aware::{compute_group_delay, unwrap_phase_degrees};
use autoeq::roomeq::GroupDelayOptimizationConfig;

/// Standard deviation of group delay (in ms) for a curve with phase data.
/// Returns None if phase data is missing or no data in passband.
pub(super) fn group_delay_std_dev(curve: &Curve, fmin: f64, fmax: f64) -> Option<f64> {
    let phase = curve.phase.as_ref()?;
    // Unwrap phase to avoid discontinuities that would cause GD spikes
    let unwrapped = unwrap_phase_degrees(phase);
    // compute_group_delay returns values in ms
    let gd = compute_group_delay(&curve.freq, &unwrapped);

    // Compute passband mean (not global mean) for accurate std dev
    let mut sum = 0.0;
    let mut count = 0usize;
    for i in 0..curve.freq.len() {
        if curve.freq[i] >= fmin && curve.freq[i] <= fmax {
            sum += gd[i];
            count += 1;
        }
    }
    if count == 0 {
        return None;
    }
    let passband_mean = sum / count as f64;

    let deviation = &gd - passband_mean;
    Some(calculate_standard_deviation_in_range(
        &curve.freq,
        &deviation,
        fmin,
        fmax,
    ))
}

pub(super) fn group_delay_qa_config(profile: GroupDelayQaProfile) -> GroupDelayOptimizationConfig {
    let mut config = GroupDelayOptimizationConfig {
        enabled: true,
        max_delay_ms: 25.0,
        min_improvement_db: -100.0,
        max_iter: GD_QA_MAX_ITER,
        popsize: 10,
        tol: 1e-6,
        ..Default::default()
    };

    match profile {
        GroupDelayQaProfile::MissingCoherenceDelayOnly => {
            config.ap_per_channel = 2;
            config.optimize_polarity = true;
            config.adaptive_allpass = false;
        }
        GroupDelayQaProfile::TrustedDelayOnly => {
            config.ap_per_channel = 0;
            config.optimize_polarity = false;
            config.adaptive_allpass = false;
        }
        GroupDelayQaProfile::FixedAllPass => {
            config.ap_per_channel = 1;
            config.optimize_polarity = true;
            config.adaptive_allpass = false;
        }
        GroupDelayQaProfile::AdaptiveAllPass => {
            config.ap_per_channel = 2;
            config.optimize_polarity = false;
            config.adaptive_allpass = true;
            config.max_iter = 4000;
            config.popsize = 25;
            config.tol = 1e-10;
        }
        GroupDelayQaProfile::PhaseLinearFir => {
            config.ap_per_channel = 0;
            config.optimize_polarity = false;
            config.adaptive_allpass = false;
        }
        GroupDelayQaProfile::MixedPhase => {
            config.ap_per_channel = 2;
            config.optimize_polarity = true;
            config.adaptive_allpass = false;
        }
    }

    config
}
